import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/idea_local_plugin.BDYmFGwK.js";import{n as a,r as o,t as s}from"./chunks/ravel_todo.BYbdUFoq.js";const c=JSON.parse(`{"title":"Migrating Mappings using Ravel","description":"Learn how to migrate your mod's obfuscation mappings using Ravel.","frontmatter":{"title":"Migrating Mappings using Ravel","description":"Learn how to migrate your mod's obfuscation mappings using Ravel.","authors":["cassiancc","deirn"],"resources":{"https://plugins.jetbrains.com/plugin/28938-ravel-remapper":"Ravel Plugin - JB Marketplace","https://github.com/badasintended/ravel":"Source Code for Ravel"},"files":[]},"headers":[],"relativePath":"develop/porting/mappings/ravel.md","filePath":"develop/porting/mappings/ravel.md","lastUpdated":1774467289000}`);var l={name:`develop/porting/mappings/ravel.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Migrating Mappings using Ravel <a class="header-anchor" href="#h1" aria-label="Permalink to “Migrating Mappings using Ravel”">​</a></h1><p><a href="https://github.com/badasintended/ravel" target="_blank" rel="noreferrer">Ravel</a> is a plugin for IntelliJ IDEA to remap source files, based on <a href="https://plugins.jetbrains.com/docs/intellij/psi.html" target="_blank" rel="noreferrer">IntelliJ&#39;s PSI</a> and <a href="https://github.com/FabricMC/mapping-io" target="_blank" rel="noreferrer">Mapping-IO</a>. It supports remapping Java, Kotlin, Mixins (written in Java), Class Tweakers, and Access Wideners.</p><p>Install it from <a href="https://plugins.jetbrains.com/plugin/28938-ravel-remapper" target="_blank" rel="noreferrer">JetBrains Marketplace</a> or download the ZIP file from <a href="https://github.com/badasintended/ravel/releases" target="_blank" rel="noreferrer">GitHub Releases</a> and install it by clicking the gear icon on the plugin settings and clicking <strong>Install Plugin From Disk</strong>.</p><p><img src="/assets/develop/misc/migrating-mappings/idea_local_plugin.png" alt="IDEA Install Plugin From Disk" loading="lazy"></p><h2 id="migrating-mappings" tabindex="-1">Migrating Mappings <a class="header-anchor" href="#migrating-mappings" aria-label="Permalink to “Migrating Mappings”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Commit any changes before attempting to remap your sources! <strong>Do not modify your <code>gradle.properties</code> or <code>build.gradle</code> yet!</strong></p></div><p>Start by right clicking on a file open in the Editor and choose <strong>Refactor</strong> &gt; <strong>Remap Using Ravel</strong></p><p><img src="/assets/develop/misc/migrating-mappings/ravel_right_click.png" alt="Right Click Menu" loading="lazy"></p><p>A dialog like this will open. You can also open the dialog by clicking <strong>Refactor</strong> from the top menu.</p><p><img src="/assets/develop/misc/migrating-mappings/ravel_dialog.png" alt="Ravel Dialog" loading="lazy"></p><p>Next, add the mappings by clicking the + icon. Click the download option if you don&#39;t have them already.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>If you do not see the download button, update Ravel to 0.3 or above.</p></div><ul><li>For migrating from Yarn to Mojang Mappings, add the Yarn <code>mappings.tiny</code> file first, choose <code>named</code> as the <strong>source</strong> namespace and <code>official</code> as the <strong>destination</strong> namespace. Then, add the Mojang <code>client.txt</code> file and choose <code>target</code> as the <strong>source</strong> namespace and <code>source</code> as the <strong>destination</strong> namespace.</li><li>For migrating from Mojang Mappings to Yarn, add the Mojang <code>client.txt</code> first, this time choosing <code>source</code> as the <strong>source</strong> and <code>target</code> as the <strong>destination</strong>. Then, add the Yarn <code>mappings.tiny</code> and choose <code>official</code> as the <strong>source</strong> and <code>named</code> as the <strong>destination</strong>.</li></ul><p>Then, select the modules that you want to remap by clicking the + icon, or the icon on its left to add all modules.</p><p>Then, click <strong>OK</strong> and wait for it to finish remapping.</p><h3 id="updating-gradle" tabindex="-1">Updating Gradle <a class="header-anchor" href="#updating-gradle" aria-label="Permalink to “Updating Gradle”">​</a></h3><p>After the remapping finished, replace your mappings in your mod&#39;s <code>build.gradle</code>.</p><div class="language-groovy line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">groovy</span><pre class="shiki shiki-themes github-light github-dark has-diff" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dependencies {</span></span>
<span class="line diff remove"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mappings </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;net.fabricmc:yarn:\${project.yarn_mappings}:v2&quot;</span></span>
<span class="line diff add"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    mappings loom</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">officialMojangMappings() </span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // Or the reverse if you&#39;re migrating from Mojang Mappings to Yarn</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Also update your <code>gradle.properties</code>, remove <code>yarn_mappings</code> option or update it to the one you use.</p><div class="language-properties line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark has-diff" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line diff remove"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">yarn_mappings</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=1.21.11+build.3 </span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="final-changes" tabindex="-1">Final Changes <a class="header-anchor" href="#final-changes" aria-label="Permalink to “Final Changes”">​</a></h3><p>That&#39;s the bulk of the work done! You&#39;ll now want to go through your source code to check for any potentially outdated Mixin targets or code that was not remapped.</p><p>For problems that are detected by Ravel, you can search (<kbd>Ctrl</kbd>+<kbd>Shift</kbd>+<kbd>F</kbd>) for <code>TODO(Ravel)</code>.</p><p><img src="/assets/develop/misc/migrating-mappings/ravel_todo.png" alt="Ravel TODO Search" loading="lazy"></p><p>Tools like <a href="https://mappings.dev/" target="_blank" rel="noreferrer">mappings.dev</a> or <a href="https://linkie.shedaniel.dev/mappings?namespace=yarn&amp;translateMode=ns&amp;translateAs=mojang_raw&amp;search=&amp;version=1.21.11" target="_blank" rel="noreferrer">Linkie</a> will be helpful to familiarize yourself with your new mappings.</p>`,25)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};